const AWS = require('aws-sdk');
const crypto = require('crypto');

const dynamodb = new AWS.DynamoDB.DocumentClient();
const TABLE_NAME = process.env.USERS_TABLE_NAME || 'Users';

const SALT_ROUNDS = 10;
const MIN_PASSWORD_LENGTH = 12;
const MAX_PASSWORD_LENGTH = 128;
const MAX_EMAIL_LENGTH = 254;

function validateEmail(email) {
  if (!email || typeof email !== 'string') {
    return false;
  }
  
  if (email.length > MAX_EMAIL_LENGTH) {
    return false;
  }
  
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  return emailRegex.test(email);
}

function validatePassword(password) {
  if (!password || typeof password !== 'string') {
    return { valid: false, message: 'Password is required' };
  }
  
  if (password.length < MIN_PASSWORD_LENGTH) {
    return { valid: false, message: `Password must be at least ${MIN_PASSWORD_LENGTH} characters long` };
  }
  
  if (password.length > MAX_PASSWORD_LENGTH) {
    return { valid: false, message: `Password must not exceed ${MAX_PASSWORD_LENGTH} characters` };
  }
  
  const hasUpperCase = /[A-Z]/.test(password);
  const hasLowerCase = /[a-z]/.test(password);
  const hasNumbers = /\d/.test(password);
  const hasSpecialChar = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password);
  
  if (!hasUpperCase || !hasLowerCase || !hasNumbers || !hasSpecialChar) {
    return { 
      valid: false, 
      message: 'Password must contain uppercase, lowercase, numbers, and special characters' 
    };
  }
  
  return { valid: true };
}

function hashPassword(password) {
  return new Promise((resolve, reject) => {
    const salt = crypto.randomBytes(16).toString('hex');
    crypto.pbkdf2(password, salt, 100000, 64, 'sha512', (err, derivedKey) => {
      if (err) reject(err);
      resolve(salt + ':' + derivedKey.toString('hex'));
    });
  });
}

function sanitizeInput(input) {
  if (typeof input !== 'string') {
    return '';
  }
  return input.trim().toLowerCase();
}

async function checkUserExists(email) {
  const params = {
    TableName: TABLE_NAME,
    Key: {
      email: email
    }
  };
  
  try {
    const result = await dynamodb.get(params).promise();
    return !!result.Item;
  } catch (error) {
    console.error('Error checking user existence:', error);
    throw error;
  }
}

async function createUser(email, hashedPassword) {
  const userId = crypto.randomUUID();
  const timestamp = new Date().toISOString();
  
  const params = {
    TableName: TABLE_NAME,
    Item: {
      email: email,
      userId: userId,
      password: hashedPassword,
      createdAt: timestamp,
      updatedAt: timestamp,
      isActive: true
    },
    ConditionExpression: 'attribute_not_exists(email)'
  };
  
  try {
    await dynamodb.put(params).promise();
    return {
      userId: userId,
      email: email,
      createdAt: timestamp
    };
  } catch (error) {
    if (error.code === 'ConditionalCheckFailedException') {
      throw new Error('User already exists');
    }
    throw error;
  }
}

exports.handler = async (event) => {
  const headers = {
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'X-XSS-Protection': '1; mode=block',
    'Cache-Control': 'no-store, no-cache, must-revalidate, private'
  };
  
  try {
    let body;
    try {
      body = JSON.parse(event.body || '{}');
    } catch (parseError) {
      return {
        statusCode: 400,
        headers: headers,
        body: JSON.stringify({ 
          error: 'Invalid JSON in request body' 
        })
      };
    }
    
    const email = sanitizeInput(body.email);
    const password = body.password;
    
    if (!validateEmail(email)) {
      return {
        statusCode: 400,
        headers: headers,
        body: JSON.stringify({ 
          error: 'Invalid email address' 
        })
      };
    }
    
    const passwordValidation = validatePassword(password);
    if (!passwordValidation.valid) {
      return {
        statusCode: 400,
        headers: headers,
        body: JSON.stringify({ 
          error: passwordValidation.message 
        })
      };
    }
    
    const userExists = await checkUserExists(email);
    if (userExists) {
      return {
        statusCode: 409,
        headers: headers,
        body: JSON.stringify({ 
          error: 'User already exists' 
        })
      };
    }
    
    const hashedPassword = await hashPassword(password);
    
    const user = await createUser(email, hashedPassword);
    
    return {
      statusCode: 201,
      headers: headers,
      body: JSON.stringify({
        message: 'User registered successfully',
        user: {
          userId: user.userId,
          email: user.email,
          createdAt: user.createdAt
        }
      })
    };
    
  } catch (error) {
    console.error('Registration error:', error);
    
    if (error.message === 'User already exists') {
      return {
        statusCode: 409,
        headers: headers,
        body: JSON.stringify({ 
          error: 'User already exists' 
        })
      };
    }
    
    return {
      statusCode: 500,
      headers: headers,
      body: JSON.stringify({ 
        error: 'Internal server error' 
      })
    };
  }
};